jQuery(document).ready(function ($) {

    // ==================== Utility Functions ====================
    const UI = {
        showLoading: () => $('#spinnerModal').removeClass('disi-hidden'),
        hideLoading: () => $('#spinnerModal').addClass('disi-hidden'),
        showToast: (message, type = 'default', duration = 2000) => {
            const toast = document.createElement('div');
            toast.className = `disi-toast disi-toast-${type}`;
            toast.textContent = message;
            document.body.appendChild(toast);
            setTimeout(() => {
                toast.classList.add('fade-out');
                toast.addEventListener('transitionend', () => toast.remove());
            }, duration);
        }
    };

    // ==================== Settings Save Functionality ====================
    class SettingsManager {
        constructor() {
            this.init();
        }

        init() {
            $('#disi_enable_admin_bar, #disi_enable_widget, #disi_enable_footer, #disi_enable_shortcode')
                .on('change', this.handleSettingChange.bind(this));
        }

        handleSettingChange(e) {
            if (typeof disiAjaxObject === 'undefined') {
                console.error('disiAjaxObject is not defined');
                return;
            }

            UI.showLoading();

            const formData = $(e.target).closest('form').serialize() +
                '&nonce=' + disiAjaxObject.nonce;

            $.ajax({
                url: disiAjaxObject.ajax_url,
                type: 'POST',
                data: formData,
                success: (response) => this.handleSuccess(response),
                error: (xhr) => this.handleError(xhr)
            });
        }

        handleSuccess(response) {
            UI.hideLoading();
            if (response.success) {
                UI.showToast(disiAjaxObject.disiLocalizeText.settingsSavedText);
            } else {
                UI.showToast(disiAjaxObject.disiLocalizeText.errorOccurredText + '：' + response.data.message, 'error');
            }
        }

        handleError(xhr) {
            UI.hideLoading();
            const errorMessages = {
                400: 'invalidRequestText',
                401: 'loginTimeoutText',
                418: 'illegalRequestText',
                403: 'loginTimeoutText'
            };

            const errorKey = errorMessages[xhr.status];
            if (errorKey) {
                UI.showToast(disiAjaxObject.disiLocalizeText[errorKey], 'error');
                if (xhr.status === 401) window.location.reload();
            } else {
                UI.showToast(`${xhr.status} ${xhr.statusText}`, 'error');
            }
        }
    }

    // ==================== PHP Info Functionality ====================
    class PHPInfoManager {
        constructor() {
            $('#btn-phpinfo-output').on('click', this.handleClick.bind(this));
        }

        handleClick() {
            if (typeof disiAjaxObject === 'undefined') return;

            UI.showLoading();

            $.ajax({
                url: disiAjaxObject.ajax_url,
                method: 'POST',
                data: { action: 'disi_get_phpinfo' },
                success: this.handleSuccess,
                error: this.handleError
            });
        }

        handleSuccess(response) {
            UI.hideLoading();
            if (response.success) {
                const newWindow = window.open('', 'phpinfo()', 'width=800,height=600');
                newWindow.document.write(`
                    <html>
                        <head><title>phpinfo()</title></head>
                        <body>${response.data.phpinfo}</body>
                    </html>
                `);
            }
        }

        handleError() {
            UI.hideLoading();
        }
    }

    // ==================== Star Rating Widget ====================
    class RatingWidget {
        constructor(containerSelector) {
            this.$container = $(containerSelector);
            this.$stars = this.$container.find('.star');
            this.$ratingInput = $('#rating-value');
            this.currentRating = 0;

            // Debug info
            console.log('RatingWidget initialized:', {
                container: this.$container.length,
                stars: this.$stars.length,
                containerSelector: containerSelector
            });

            if (this.$stars.length === 0) {
                console.error('No stars found! Check HTML structure');
                return;
            }

            this.init();
        }

        init() {
            this.bindEvents();
            window.ratingWidget = this; // Expose to external
            this.displayRating(0); // Initialize with empty stars
        }

        bindEvents() {
            this.$stars.on('mousemove', (e) => this.handleMouseMove(e));
            this.$stars.on('click', (e) => this.handleClick(e));
            this.$container.on('mouseleave', () => this.displayRating(this.currentRating));
        }

        handleMouseMove(e) {
            const $star = $(e.target);
            const starValue = parseFloat($star.data('value'));
            const isLeftHalf = e.offsetX < $star.width() / 2;

            // Remove classes before bulk operations
            this.$stars.removeClass('hover half');

            if (isLeftHalf) {
                $star.addClass('half').attr('data-hover-value', starValue - 0.5);
            } else {
                $star.addClass('hover').attr('data-hover-value', starValue);
            }

            $star.nextAll('.star').removeClass('hover half');
        }

        handleClick(e) {
            const $star = $(e.target);
            const value = e.offsetX < $star.width() / 2
                ? parseFloat($star.data('value')) - 0.5
                : parseFloat($star.data('value'));

            this.setRating(value);
        }

        setRating(value) {
            this.currentRating = value;
            this.$ratingInput.val(value).trigger('change');
            this.displayRating(value);
        }

        displayRating(value) {
            this.$stars.removeClass('selected half-selected hover half');

            if (value === 0) return;

            this.$stars.each((_, star) => {
                const $star = $(star);
                const starValue = parseFloat($star.data('value'));

                if (value >= starValue) {
                    $star.addClass('selected');
                } else if (value >= starValue - 0.5 && value < starValue) {
                    $star.addClass('half-selected');
                }
            });
        }

        getRating() {
            return this.currentRating;
        }

        reset() {
            this.setRating(0);
        }
    }

    // ==================== Feedback Form Functionality ====================
    class FeedbackManager {
        constructor(ratingWidget) {
            this.ratingWidget = ratingWidget;
            this.init();
        }

        init() {
            $('#disi_send_feedback').on('click', () => this.submit());
        }

        submit() {
            const data = {
                rating: this.ratingWidget.getRating(),
                type: $('#disi_feedback_type').val(),
                message: $('#disi_feedback_message').val(),
                email: $('#disi_feedback_email').val()
            };

            // Validation with toast messages
            if (!data.type) {
                UI.showToast('Please select feedback type', 'warning');
                return;
            }

            if (data.rating === 0 && (!data.message || data.message.trim() === '')) {
                UI.showToast('Please either rate or write something', 'warning');
                return;
            }

            UI.showLoading();

            const finalMessage = data.message && data.message.trim() !== ''
                ? data.message.trim()
                : '[No message provided]';

            $.ajax({
                url: ajaxurl,
                type: 'POST',
                data: {
                    action: 'disi_send_feedback',
                    rating: data.rating,
                    feedback_type: data.type,
                    message: finalMessage,
                    user_email: data.email,
                    nonce: disiAjaxObject.nonce
                },
                success: (response) => this.handleSuccess(response),
                error: () => this.handleError(),
                complete: () => {
                    UI.hideLoading();
                }
            });
        }

        handleSuccess(response) {
            if (response.success) {
                UI.showToast('Thank you for your feedback!', 'success');
                this.resetForm();
            } else {
                UI.showToast('Error: ' + response.data, 'error');
            }
        }

        handleError() {
            UI.showToast('An error occurred. Please try again.', 'error');
        }

        resetForm() {
            $('#disi_feedback_type').val('general');
            $('#disi_feedback_message').val('');
            $('#disi_feedback_email').val('');
            this.ratingWidget.reset();
        }
    }

    // ==================== Initialize All Features ====================
    // Use setTimeout to ensure all elements are rendered
    setTimeout(function() {
        if (typeof disiAjaxObject !== 'undefined') {
            new SettingsManager();
            new PHPInfoManager();

            // Check if container exists
            if ($('#rating-container').length) {
                const ratingWidget = new RatingWidget('#rating-container');
                new FeedbackManager(ratingWidget);
            } else {
                console.error('Rating container not found!');
            }
        }
    }, 100);
});